Here's an example of how to implement smart enumerations in C#:

```csharp
public enum Color
{
    Red,
    Green,
    Blue
}

public class ColorValueObject
{
    public ColorValueObject(Color color)
    {
        if (color == Color.None)
        {
            throw new ArgumentException("Color cannot be None", nameof(color));
        }

        Color = color;
    }

    public Color Color { get; private set; }

    public static implicit operator Color(ColorValueObject valueObject) => valueObject.Color;

    public static ColorValueObject FromString(string color)
    {
        return color switch
        {
            "Red" => new ColorValueObject(Color.Red),
            "Green" => new ColorValueObject(Color.Green),
            "Blue" => new ColorValueObject(Color.Blue),
            _ => throw new ArgumentException("Invalid color", nameof(color)),
        };
    }

    public override string ToString() => Color.ToString();
}
```

